import React, { useState } from "react";

const AnadirItem = () => {
  const [formulario, setFormulario] = useState({
    nombre_item: "",
    tipo_item: false,
    descripcion: "",
    id_servicio: "",
    duracion: "",
    modalidad: "",
    url: "",
  });

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormulario({
      ...formulario,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Datos del ítem:", formulario);
    alert("Ítem registrado correctamente (solo frontend)");
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4">Añadir Ítem</h2>
      <form onSubmit={handleSubmit} className="space-y-4">

        <div>
          <label className="block font-medium">Nombre del Ítem</label>
          <input
            type="text"
            name="nombre_item"
            value={formulario.nombre_item}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
            maxLength={100}
            required
          />
        </div>

        <div className="flex items-center space-x-2">
          <input
            type="checkbox"
            name="tipo_item"
            checked={formulario.tipo_item}
            onChange={handleChange}
            className="w-5 h-5"
          />
          <label className="font-medium">¿Es un servicio?</label>
        </div>

        {formulario.tipo_item && (
          <div className="space-y-4 mt-4">
            <div>
              <label className="block font-medium">ID Servicio</label>
              <input
                type="number"
                name="id_servicio"
                value={formulario.id_servicio}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded p-2"
                required
              />
            </div>

            <div>
              <label className="block font-medium">Duración (en minutos)</label>
              <input
                type="number"
                name="duracion"
                value={formulario.duracion}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded p-2"
                required
              />
            </div>

            <div>
              <label className="block font-medium">Modalidad</label>
              <input
                type="text"
                name="modalidad"
                value={formulario.modalidad}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded p-2"
                maxLength={100}
                required
              />
            </div>

            <div>
              <label className="block font-medium">URL</label>
              <input
                type="url"
                name="url"
                value={formulario.url}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded p-2"
                maxLength={200}
                required
              />
            </div>
          </div>
        )}

        <div>
          <label className="block font-medium">Descripción</label>
          <textarea
            name="descripcion"
            value={formulario.descripcion}
            onChange={handleChange}
            className="w-full border border-gray-300 rounded p-2"
            maxLength={100}
            required
          />
        </div>

        <button
          type="submit"
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          Guardar Ítem
        </button>
      </form>
    </div>
  );
};

export default AnadirItem;
